
using namespace System.Management.Automation
using namespace System.Management.Automation.Language

Register-ArgumentCompleter -Native -CommandName 'deno' -ScriptBlock {
    param($wordToComplete, $commandAst, $cursorPosition)

    $commandElements = $commandAst.CommandElements
    $command = @(
        'deno'
        for ($i = 1; $i -lt $commandElements.Count; $i++) {
            $element = $commandElements[$i]
            if ($element -isnot [StringConstantExpressionAst] -or
                $element.StringConstantType -ne [StringConstantType]::BareWord -or
                $element.Value.StartsWith('-') -or
                $element.Value -eq $wordToComplete) {
                break
        }
        $element.Value
    }) -join ';'

    $completions = @(switch ($command) {
        'deno' {
            [CompletionResult]::new('--no-check', '--no-check', [CompletionResultType]::ParameterName, 'Skip type-checking. If the value of "remote" is supplied, diagnostic errors from remote modules will be ignored')
            [CompletionResult]::new('--import-map', '--import-map', [CompletionResultType]::ParameterName, 'Load import map file from local file or remote URL   Docs: https://docs.deno.com/runtime/manual/basics/import_maps')
            [CompletionResult]::new('--node-modules-dir', '--node-modules-dir', [CompletionResultType]::ParameterName, 'Selects the node_modules directory mode for npm packages (not a path). One of: auto (create a local node_modules directory and install npm packages into it), manual (use the existing local node_modules directory, do not modify it), none (do not use a local node_modules directory; resolve npm packages from the global cache). Defaults to auto when the flag is passed without a value.')
            [CompletionResult]::new('--node-modules-linker', '--node-modules-linker', [CompletionResultType]::ParameterName, 'Sets the linker mode for npm packages (isolated or hoisted)')
            [CompletionResult]::new('--vendor', '--vendor', [CompletionResultType]::ParameterName, 'Toggles local vendor folder usage for remote modules and a node_modules folder for npm packages')
            [CompletionResult]::new('--conditions', '--conditions', [CompletionResultType]::ParameterName, 'Use this argument to specify custom conditions for npm package exports. You can also use DENO_CONDITIONS env var.  Docs: https://docs.deno.com/go/conditional-exports')
            [CompletionResult]::new('-c', '-c', [CompletionResultType]::ParameterName, 'Configure different aspects of deno including TypeScript, linting, and code formatting.   Typically the configuration file will be called `deno.json` or `deno.jsonc` and   automatically detected; in that case this flag is not necessary.   Docs: https://docs.deno.com/go/config')
            [CompletionResult]::new('--config', '--config', [CompletionResultType]::ParameterName, 'Configure different aspects of deno including TypeScript, linting, and code formatting.   Typically the configuration file will be called `deno.json` or `deno.jsonc` and   automatically detected; in that case this flag is not necessary.   Docs: https://docs.deno.com/go/config')
            [CompletionResult]::new('-r', '-r', [CompletionResultType]::ParameterName, 'Reload source code cache (recompile TypeScript). With no value, reloads everything. Pass a comma-separated list of specifiers to reload only those modules; npm: reloads all npm modules; npm:chalk reloads a single npm module; jsr:@std/http/file-server,jsr:@std/assert/assert-equals reloads specific modules.')
            [CompletionResult]::new('--reload', '--reload', [CompletionResultType]::ParameterName, 'Reload source code cache (recompile TypeScript). With no value, reloads everything. Pass a comma-separated list of specifiers to reload only those modules; npm: reloads all npm modules; npm:chalk reloads a single npm module; jsr:@std/http/file-server,jsr:@std/assert/assert-equals reloads specific modules.')
            [CompletionResult]::new('--lock', '--lock', [CompletionResultType]::ParameterName, 'Check the specified lock file. (If value is not provided, defaults to "./deno.lock")')
            [CompletionResult]::new('--frozen', '--frozen', [CompletionResultType]::ParameterName, 'Error out if lockfile is out of date')
            [CompletionResult]::new('--cert', '--cert', [CompletionResultType]::ParameterName, 'Load certificate authority from PEM encoded file')
            [CompletionResult]::new('--unsafely-ignore-certificate-errors', '--unsafely-ignore-certificate-errors', [CompletionResultType]::ParameterName, 'DANGER: Disables verification of TLS certificates')
            [CompletionResult]::new('--minimum-dependency-age', '--minimum-dependency-age', [CompletionResultType]::ParameterName, '(Unstable) The age in minutes, ISO-8601 duration or RFC3339 absolute timestamp (e.g. ''120'' for two hours, ''P2D'' for two days, ''2025-09-16'' for cutoff date, ''2025-09-16T12:00:00+00:00'' for cutoff time, ''0'' to disable)')
            [CompletionResult]::new('-P', '-P ', [CompletionResultType]::ParameterName, 'P')
            [CompletionResult]::new('--permission-set', '--permission-set', [CompletionResultType]::ParameterName, 'permission-set')
            [CompletionResult]::new('-R', '-R ', [CompletionResultType]::ParameterName, 'R')
            [CompletionResult]::new('--allow-read', '--allow-read', [CompletionResultType]::ParameterName, 'allow-read')
            [CompletionResult]::new('--deny-read', '--deny-read', [CompletionResultType]::ParameterName, 'deny-read')
            [CompletionResult]::new('--ignore-read', '--ignore-read', [CompletionResultType]::ParameterName, 'ignore-read')
            [CompletionResult]::new('-W', '-W ', [CompletionResultType]::ParameterName, 'W')
            [CompletionResult]::new('--allow-write', '--allow-write', [CompletionResultType]::ParameterName, 'allow-write')
            [CompletionResult]::new('--deny-write', '--deny-write', [CompletionResultType]::ParameterName, 'deny-write')
            [CompletionResult]::new('-N', '-N ', [CompletionResultType]::ParameterName, 'N')
            [CompletionResult]::new('--allow-net', '--allow-net', [CompletionResultType]::ParameterName, 'allow-net')
            [CompletionResult]::new('--deny-net', '--deny-net', [CompletionResultType]::ParameterName, 'deny-net')
            [CompletionResult]::new('-E', '-E ', [CompletionResultType]::ParameterName, 'E')
            [CompletionResult]::new('--allow-env', '--allow-env', [CompletionResultType]::ParameterName, 'allow-env')
            [CompletionResult]::new('--deny-env', '--deny-env', [CompletionResultType]::ParameterName, 'deny-env')
            [CompletionResult]::new('--ignore-env', '--ignore-env', [CompletionResultType]::ParameterName, 'ignore-env')
            [CompletionResult]::new('-S', '-S ', [CompletionResultType]::ParameterName, 'S')
            [CompletionResult]::new('--allow-sys', '--allow-sys', [CompletionResultType]::ParameterName, 'allow-sys')
            [CompletionResult]::new('--deny-sys', '--deny-sys', [CompletionResultType]::ParameterName, 'deny-sys')
            [CompletionResult]::new('--allow-run', '--allow-run', [CompletionResultType]::ParameterName, 'allow-run')
            [CompletionResult]::new('--deny-run', '--deny-run', [CompletionResultType]::ParameterName, 'deny-run')
            [CompletionResult]::new('--allow-ffi', '--allow-ffi', [CompletionResultType]::ParameterName, 'allow-ffi')
            [CompletionResult]::new('--deny-ffi', '--deny-ffi', [CompletionResultType]::ParameterName, 'deny-ffi')
            [CompletionResult]::new('-I', '-I ', [CompletionResultType]::ParameterName, 'Allow importing from remote hosts. Optionally specify allowed IP addresses and host names, with ports as necessary. Default value: deno.land:443,jsr.io:443,esm.sh:443,raw.esm.sh:443,cdn.jsdelivr.net:443,raw.githubusercontent.com:443,gist.githubusercontent.com:443')
            [CompletionResult]::new('--allow-import', '--allow-import', [CompletionResultType]::ParameterName, 'Allow importing from remote hosts. Optionally specify allowed IP addresses and host names, with ports as necessary. Default value: deno.land:443,jsr.io:443,esm.sh:443,raw.esm.sh:443,cdn.jsdelivr.net:443,raw.githubusercontent.com:443,gist.githubusercontent.com:443')
            [CompletionResult]::new('--deny-import', '--deny-import', [CompletionResultType]::ParameterName, 'Deny importing from remote hosts. Optionally specify denied IP addresses and host names, with ports as necessary.')
            [CompletionResult]::new('--inspect', '--inspect', [CompletionResultType]::ParameterName, 'Activate inspector on host:port [default: 127.0.0.1:9229]. Host and port are optional. Using port 0 will assign a random free port.')
            [CompletionResult]::new('--inspect-brk', '--inspect-brk', [CompletionResultType]::ParameterName, 'Activate inspector on host:port, wait for debugger to connect and break at the start of user script')
            [CompletionResult]::new('--inspect-wait', '--inspect-wait', [CompletionResultType]::ParameterName, 'Activate inspector on host:port and wait for debugger to connect before running user code')
            [CompletionResult]::new('--inspect-publish-uid', '--inspect-publish-uid', [CompletionResultType]::ParameterName, 'inspect-publish-uid')
            [CompletionResult]::new('--allow-scripts', '--allow-scripts', [CompletionResultType]::ParameterName, 'Allow running npm lifecycle scripts for the given packages   Note: Scripts will only be executed when using a node_modules directory (`--node-modules-dir`)')
            [CompletionResult]::new('--location', '--location', [CompletionResultType]::ParameterName, 'Value of globalThis.location used by some web APIs')
            [CompletionResult]::new('--v8-flags', '--v8-flags', [CompletionResultType]::ParameterName, 'To see a list of all available flags use --v8-flags=--help   Flags can also be set via the DENO_V8_FLAGS environment variable.   Any flags set with this flag are appended after the DENO_V8_FLAGS environment variable')
            [CompletionResult]::new('--seed', '--seed', [CompletionResultType]::ParameterName, 'Set the random number generator seed')
            [CompletionResult]::new('--trace-ops', '--trace-ops', [CompletionResultType]::ParameterName, 'Trace low-level op calls')
            [CompletionResult]::new('--preload', '--preload', [CompletionResultType]::ParameterName, 'A list of files that will be executed before the main module')
            [CompletionResult]::new('--require', '--require', [CompletionResultType]::ParameterName, 'A list of CommonJS modules that will be executed before the main module')
            [CompletionResult]::new('--check', '--check', [CompletionResultType]::ParameterName, 'Enable type-checking. This subcommand does not type-check by default; pass --check=all to also type-check remote modules. Alternatively, use the ''deno check'' subcommand.')
            [CompletionResult]::new('--watch', '--watch', [CompletionResultType]::ParameterName, 'Watch for file changes and restart process automatically.   Local files from entry point module graph are watched by default.   Additional paths might be watched by passing them as arguments to this flag.')
            [CompletionResult]::new('--watch-hmr', '--watch-hmr', [CompletionResultType]::ParameterName, 'Watch for file changes and hot-replace modules. The process restarts if hot replacement fails.   Local files from entry point module graph are watched by default.   Additional paths might be watched by passing them as arguments to this flag.')
            [CompletionResult]::new('--watch-exclude', '--watch-exclude', [CompletionResultType]::ParameterName, 'Exclude provided files/patterns from watch mode')
            [CompletionResult]::new('--ext', '--ext', [CompletionResultType]::ParameterName, 'Set content type of the supplied file')
            [CompletionResult]::new('--env-file', '--env-file', [CompletionResultType]::ParameterName, 'Load environment variables from local file   Only the first environment variable with a given key is used.   Existing process environment variables are not overwritten, so if variables with the same names already exist in the environment, their values will be preserved.   Where multiple declarations for the same environment variable exist in your .env file, the first one encountered is applied. This is determined by the order of the files you pass as arguments.')
            [CompletionResult]::new('--coverage', '--coverage', [CompletionResultType]::ParameterName, 'Collect coverage profile data into DIR. If DIR is not specified, it uses ''coverage/''.   This option can also be set via the DENO_COVERAGE_DIR environment variable.')
            [CompletionResult]::new('--cpu-prof-dir', '--cpu-prof-dir', [CompletionResultType]::ParameterName, 'Directory where the V8 CPU profiles will be written. Implicitly enables --cpu-prof')
            [CompletionResult]::new('--cpu-prof-name', '--cpu-prof-name', [CompletionResultType]::ParameterName, 'Filename for the CPU profile (defaults to CPU.<timestamp>.<pid>.cpuprofile)')
            [CompletionResult]::new('--cpu-prof-interval', '--cpu-prof-interval', [CompletionResultType]::ParameterName, 'Sampling interval in microseconds for CPU profiling (default: 1000)')
            [CompletionResult]::new('-t', '-t', [CompletionResultType]::ParameterName, 'Execute tasks with a tunnel to Deno Deploy.      Create a secure connection between your local machine and Deno Deploy,     providing access to centralised environment variables, logging,     and serving from your local environment to the public internet')
            [CompletionResult]::new('--tunnel', '--tunnel', [CompletionResultType]::ParameterName, 'Execute tasks with a tunnel to Deno Deploy.      Create a secure connection between your local machine and Deno Deploy,     providing access to centralised environment variables, logging,     and serving from your local environment to the public internet')
            [CompletionResult]::new('-h', '-h', [CompletionResultType]::ParameterName, 'h')
            [CompletionResult]::new('--help', '--help', [CompletionResultType]::ParameterName, 'help')
            [CompletionResult]::new('-L', '-L ', [CompletionResultType]::ParameterName, 'Set log level')
            [CompletionResult]::new('--log-level', '--log-level', [CompletionResultType]::ParameterName, 'Set log level')
            [CompletionResult]::new('--no-remote', '--no-remote', [CompletionResultType]::ParameterName, 'Do not resolve remote modules')
            [CompletionResult]::new('--no-npm', '--no-npm', [CompletionResultType]::ParameterName, 'Do not resolve npm modules')
            [CompletionResult]::new('--no-config', '--no-config', [CompletionResultType]::ParameterName, 'Disable automatic loading of the configuration file')
            [CompletionResult]::new('--no-lock', '--no-lock', [CompletionResultType]::ParameterName, 'Disable auto discovery of the lock file')
            [CompletionResult]::new('-A', '-A ', [CompletionResultType]::ParameterName, 'Allow all permissions')
            [CompletionResult]::new('--allow-all', '--allow-all', [CompletionResultType]::ParameterName, 'Allow all permissions')
            [CompletionResult]::new('--allow-hrtime', '--allow-hrtime', [CompletionResultType]::ParameterName, 'allow-hrtime')
            [CompletionResult]::new('--deny-hrtime', '--deny-hrtime', [CompletionResultType]::ParameterName, 'deny-hrtime')
            [CompletionResult]::new('--no-prompt', '--no-prompt', [CompletionResultType]::ParameterName, 'no-prompt')
            [CompletionResult]::new('--cached-only', '--cached-only', [CompletionResultType]::ParameterName, 'Require that remote dependencies are already cached')
            [CompletionResult]::new('--enable-testing-features-do-not-use', '--enable-testing-features-do-not-use', [CompletionResultType]::ParameterName, 'INTERNAL: Enable internal features used during integration testing')
            [CompletionResult]::new('--eszip-internal-do-not-use', '--eszip-internal-do-not-use', [CompletionResultType]::ParameterName, 'eszip-internal-do-not-use')
            [CompletionResult]::new('--no-clear-screen', '--no-clear-screen', [CompletionResultType]::ParameterName, 'Do not clear terminal screen when under watch mode')
            [CompletionResult]::new('--no-code-cache', '--no-code-cache', [CompletionResultType]::ParameterName, 'Disable V8 code cache feature')
            [CompletionResult]::new('--cpu-prof', '--cpu-prof', [CompletionResultType]::ParameterName, 'Start the V8 CPU profiler on startup and write the profile to disk on exit. Profiles are written to the current directory by default')
            [CompletionResult]::new('--cpu-prof-md', '--cpu-prof-md', [CompletionResultType]::ParameterName, 'Generate a human-readable markdown report alongside the CPU profile')
            [CompletionResult]::new('--cpu-prof-flamegraph', '--cpu-prof-flamegraph', [CompletionResultType]::ParameterName, 'Generate an SVG flamegraph alongside the CPU profile')
            [CompletionResult]::new('--use-env-proxy', '--use-env-proxy', [CompletionResultType]::ParameterName, 'Use HTTP_PROXY, HTTPS_PROXY, and NO_PROXY for node:http/node:https')
            [CompletionResult]::new('--no-use-env-proxy', '--no-use-env-proxy', [CompletionResultType]::ParameterName, 'no-use-env-proxy')
            [CompletionResult]::new('--unstable', '--unstable', [CompletionResultType]::ParameterName, 'The `--unstable` flag has been deprecated. Use granular `--unstable-*` flags instead   To view the list of individual unstable feature flags, run this command again with --help=unstable')
            [CompletionResult]::new('--unstable-bare-node-builtins', '--unstable-bare-node-builtins', [CompletionResultType]::ParameterName, 'Enable unstable bare node builtins feature')
            [CompletionResult]::new('--unstable-broadcast-channel', '--unstable-broadcast-channel', [CompletionResultType]::ParameterName, 'Enable unstable `BroadcastChannel` API')
            [CompletionResult]::new('--unstable-bundle', '--unstable-bundle', [CompletionResultType]::ParameterName, 'Enable unstable bundle runtime API')
            [CompletionResult]::new('--unstable-byonm', '--unstable-byonm', [CompletionResultType]::ParameterName, 'unstable-byonm')
            [CompletionResult]::new('--unstable-cron', '--unstable-cron', [CompletionResultType]::ParameterName, 'Enable unstable `Deno.cron` API')
            [CompletionResult]::new('--unstable-detect-cjs', '--unstable-detect-cjs', [CompletionResultType]::ParameterName, 'Treats ambiguous .js, .jsx, .ts, .tsx files as CommonJS modules in more cases')
            [CompletionResult]::new('--unstable-ffi', '--unstable-ffi', [CompletionResultType]::ParameterName, 'Enable unstable FFI APIs')
            [CompletionResult]::new('--unstable-fs', '--unstable-fs', [CompletionResultType]::ParameterName, 'Enable unstable file system APIs')
            [CompletionResult]::new('--unstable-http', '--unstable-http', [CompletionResultType]::ParameterName, 'Enable unstable HTTP APIs')
            [CompletionResult]::new('--unstable-kv', '--unstable-kv', [CompletionResultType]::ParameterName, 'Enable unstable KV APIs')
            [CompletionResult]::new('--unstable-lazy-dynamic-imports', '--unstable-lazy-dynamic-imports', [CompletionResultType]::ParameterName, 'Lazily loads statically analyzable dynamic imports when not running with type checking. Warning: This may change the order of semver specifier resolution.')
            [CompletionResult]::new('--unstable-lockfile-v5', '--unstable-lockfile-v5', [CompletionResultType]::ParameterName, 'Enable unstable lockfile v5')
            [CompletionResult]::new('--unstable-net', '--unstable-net', [CompletionResultType]::ParameterName, 'enable unstable net APIs')
            [CompletionResult]::new('--unstable-no-legacy-abort', '--unstable-no-legacy-abort', [CompletionResultType]::ParameterName, 'Enable abort signal in Deno.serve without legacy behavior. This will not abort the server when the request is handled successfully.')
            [CompletionResult]::new('--unstable-node-globals', '--unstable-node-globals', [CompletionResultType]::ParameterName, 'Deprecated. Node.js `setTimeout` and `setInterval` globals are now always enabled, so this flag has no effect.')
            [CompletionResult]::new('--unstable-npm-lazy-caching', '--unstable-npm-lazy-caching', [CompletionResultType]::ParameterName, 'Enable unstable lazy caching of npm dependencies, downloading them only as needed (disabled: all npm packages in package.json are installed on startup; enabled: only npm packages that are actually referenced in an import are installed')
            [CompletionResult]::new('--unstable-otel', '--unstable-otel', [CompletionResultType]::ParameterName, 'Enable unstable OpenTelemetry features')
            [CompletionResult]::new('--unstable-process', '--unstable-process', [CompletionResultType]::ParameterName, 'Enable unstable process APIs')
            [CompletionResult]::new('--unstable-raw-imports', '--unstable-raw-imports', [CompletionResultType]::ParameterName, 'Enable unstable ''bytes'' imports.')
            [CompletionResult]::new('--unstable-sloppy-imports', '--unstable-sloppy-imports', [CompletionResultType]::ParameterName, 'Enable unstable resolving of specifiers by extension probing, .js to .ts, and directory probing')
            [CompletionResult]::new('--unstable-subdomain-wildcards', '--unstable-subdomain-wildcards', [CompletionResultType]::ParameterName, 'Enable subdomain wildcards support for the `--allow-net` flag')
            [CompletionResult]::new('--unstable-temporal', '--unstable-temporal', [CompletionResultType]::ParameterName, 'Enable unstable Temporal API')
            [CompletionResult]::new('--unstable-tsgo', '--unstable-tsgo', [CompletionResultType]::ParameterName, 'Enable unstable TypeScript Go integration')
            [CompletionResult]::new('--unstable-unsafe-proto', '--unstable-unsafe-proto', [CompletionResultType]::ParameterName, 'Enable unsafe __proto__ support. This is a security risk.')
