            [CompletionResult]::new('--unstable-webgpu', '--unstable-webgpu', [CompletionResultType]::ParameterName, 'Enable unstable WebGPU APIs')
            [CompletionResult]::new('--unstable-worker-options', '--unstable-worker-options', [CompletionResultType]::ParameterName, 'Enable unstable Web Worker APIs')
            [CompletionResult]::new('-V', '-V ', [CompletionResultType]::ParameterName, 'Print version')
            [CompletionResult]::new('--version', '--version', [CompletionResultType]::ParameterName, 'Print version')
            [CompletionResult]::new('-q', '-q', [CompletionResultType]::ParameterName, 'Suppress diagnostic output')
            [CompletionResult]::new('--quiet', '--quiet', [CompletionResultType]::ParameterName, 'Suppress diagnostic output')
            [CompletionResult]::new('run', 'run', [CompletionResultType]::ParameterValue, 'Run a JavaScript or TypeScript program, or a task or script.  By default all programs are run in sandbox without access to disk, network or ability to spawn subprocesses.   deno run https://docs.deno.com/hello_world.ts  Grant permission to read from disk and listen to network:   deno run --allow-read --allow-net jsr:@std/http/file-server  Grant permission to read allow-listed files from disk:   deno run --allow-read=/etc jsr:@std/http/file-server  Grant all permissions:   deno run -A jsr:@std/http/file-server  Specifying the filename ''-'' to read the file from stdin.   curl https://docs.deno.com/hello_world.ts | deno run -  Read more: https://docs.deno.com/go/run')
            [CompletionResult]::new('watch', 'watch', [CompletionResultType]::ParameterValue, 'Run a JavaScript or TypeScript program, watching for file changes and hot-replacing modules.  This is an alias for deno run --watch-hmr. The process restarts if hot replacement fails.   deno watch main.ts  Local files from the entry point module graph are watched by default. Additional paths can be passed with --watch-hmr:   deno watch --watch-hmr=./templates main.ts  Read more: https://docs.deno.com/go/run')
            [CompletionResult]::new('serve', 'serve', [CompletionResultType]::ParameterValue, 'Run a server defined in a main module  The serve command uses the default exports of the main module to determine which servers to start.  Start a server defined in server.ts:   deno serve server.ts  Start a server defined in server.ts, watching for changes and running on port 5050:   deno serve --watch --port 5050 server.ts  Read more: https://docs.deno.com/go/serve')
            [CompletionResult]::new('add', 'add', [CompletionResultType]::ParameterValue, 'Add dependencies to your configuration file.   deno add express  Unprefixed packages default to npm. Use jsr: prefix for jsr packages:   deno add jsr:@std/path  Or multiple dependencies at once:   deno add express jsr:@std/path')
            [CompletionResult]::new('audit', 'audit', [CompletionResultType]::ParameterValue, 'Audit currently installed dependencies.   deno audit  Show only high and critical severity vulnerabilities   deno audit --level=high  Check against socket.dev vulnerability database   deno audit --socket  Don''t error if the audit data can''t be retrieved from the registry   deno audit --ignore-registry-errors')
            [CompletionResult]::new('remove', 'remove', [CompletionResultType]::ParameterValue, 'Remove dependencies from the configuration file.   deno remove @std/path  You can remove multiple dependencies at once:   deno remove @std/path @std/assert  With the --global flag, this is an alias for deno uninstall --global and removes a globally installed executable script:   deno remove --global file_server ')
            [CompletionResult]::new('bench', 'bench', [CompletionResultType]::ParameterValue, 'Run benchmarks using Deno''s built-in bench tool.  Evaluate the given files, run all benches declared with ''Deno.bench()'' and report results to standard output:   deno bench src/fetch_bench.ts src/signal_bench.ts  If you specify a directory instead of a file, the path is expanded to all contained files matching the glob {*_,*.,}bench.{js,mjs,ts,mts,jsx,tsx}:   deno bench src/  Read more: https://docs.deno.com/go/bench')
            [CompletionResult]::new('bundle', 'bundle', [CompletionResultType]::ParameterValue, 'Output a single JavaScript file with all dependencies.    deno bundle jsr:@std/http/file-server -o file-server.bundle.js  If no output file is given, the output is written to standard output:    deno bundle jsr:@std/http/file-server ')
            [CompletionResult]::new('cache', 'cache', [CompletionResultType]::ParameterValue, 'Cache and compile remote dependencies.  Download and compile a module with all of its static dependencies and save them in the local cache, without running any code:   deno cache jsr:@std/http/file-server  Future runs of this module will trigger no downloads or compilation unless --reload is specified  Read more: https://docs.deno.com/go/cache')
            [CompletionResult]::new('check', 'check', [CompletionResultType]::ParameterValue, 'Download and type-check without execution.    deno check jsr:@std/http/file-server  Unless --reload is specified, this command will not re-download already cached dependencies  Read more: https://docs.deno.com/go/check')
            [CompletionResult]::new('clean', 'clean', [CompletionResultType]::ParameterValue, 'Remove the cache directory ($DENO_DIR)')
            [CompletionResult]::new('compile', 'compile', [CompletionResultType]::ParameterValue, 'Compiles the given script into a self contained executable.    deno compile --allow-read --allow-net jsr:@std/http/file-server   deno compile --output file_server jsr:@std/http/file-server  Any flags specified which affect runtime behavior will be applied to the resulting binary.  This allows distribution of a Deno application to systems that do not have Deno installed. Under the hood, it bundles a slimmed down version of the Deno runtime along with your JavaScript or TypeScript code.  Cross-compiling to different target architectures is supported using the --target flag. On the first invocation of `deno compile`, Deno will download the relevant binary and cache it in $DENO_DIR.  Read more: https://docs.deno.com/go/compile ')
            [CompletionResult]::new('create', 'create', [CompletionResultType]::ParameterValue, 'scaffolds a project from a package')
            [CompletionResult]::new('desktop', 'desktop', [CompletionResultType]::ParameterValue, 'Build and run desktop applications.    deno desktop main.tsx   deno desktop --hmr main.tsx   deno desktop --output MyApp.app main.tsx   deno desktop  Compiles the given script into a desktop application using a backend for the UI layer. The entrypoint can be a file, or omitted (or .) to auto-detect a supported framework (Next.js, Astro, etc.) in the current directory.  Read more: https://docs.deno.com/go/desktop ')
